#include <vector>

namespace query_course_enrollment_stats {

struct Course {
  sqlgen::PrimaryKey<int> course_id;
  std::string title;
};

struct Enrollment {
  sqlgen::PrimaryKey<int> enrollment_id;
  sqlgen::ForeignKey<int, Course, "course_id"> course_id;
  std::optional<float> grade;
};

struct CourseStats {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

struct CourseStatsView {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

/**
 * Function: Calculate enrollment statistics per course.
 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen::literals;

  // 1. Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // 2. Create tables
  (sqlgen::create_table<Course> | sqlgen::if_not_exists)(conn);
  (sqlgen::create_table<Enrollment> | sqlgen::if_not_exists)(conn);

  // 3. Build and execute the query
  auto result = (sqlgen::select_from<Course, "c">(
        "title"_c,
        sqlgen::count("e.enrollment_id"_c).as<"student_count">(),
        sqlgen::avg("e.grade"_c).as<"avg_grade">()
      )
      | sqlgen::left_join<Enrollment, "e">("c.course_id"_c == "e.course_id"_c)
      | sqlgen::group_by("c.course_id"_c, "c.title"_c)
      | sqlgen::to<std::vector<CourseStatsView>>
    )(conn);

  // 4. Convert results to CourseStats format
  std::vector<CourseStats> stats;
  for (const auto& view : result) {
    stats.push_back(CourseStats{
        .title = view.title,
        .student_count = view.student_count,
        .avg_grade = view.avg_grade
    });
  }

  return stats;
}

}  // namespace query_course_enrollment_stats
