  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // 2. Create tables with proper constraints
  auto create_parent = sqlgen::create_table<Parent>;
  auto create_child = sqlgen::create_table<Child>;

  // Drop tables if they exist to start fresh
  auto drop_parent = sqlgen::drop<Parent> | sqlgen::if_exists;
  auto drop_child = sqlgen::drop<Child> | sqlgen::if_exists;

  // Execute drop operations
  if (!drop_parent(conn) || !drop_child(conn)) {
    return false;
  }

  // Create tables
  if (!create_parent(conn) || !create_child(conn)) {
    return false;
  }

  // 3. Insert parent and child records with the same parent_id
  Parent parent{1, "Test Parent"};
  Child child{1, 1, "Test Child Note"};

  // Insert parent and child
  auto insert_result = sqlgen::insert(conn, parent, child);
  if (!insert_result) {
    return false;
  }

  // 4. Delete parent and check if child is automatically deleted
  auto delete_result = sqlgen::delete_from<Parent>(conn);
  if (!delete_result) {
    return false;
  }

  // 5. Verify if child was deleted
  auto children_result = sqlgen::read<std::vector<Child>>(conn);
  if (!children_result) {
    return false;
  }

  // If the vector is empty, child was deleted via cascade
  return children_result->empty();
}

}  // namespace cascade_delete_demo

