```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <unordered_map>

namespace update_inventory_stock {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int stock;
};

bool update_inventory_stock(const std::unordered_map<int, int>& received) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to database
  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) return false;

  // Create table if not exists
  auto create_res = create_table<Product>(conn_res.value());
  if (!create_res) return false;

  // Begin transaction
  auto begin_res = begin_transaction(conn_res.value());
  if (!begin_res) return false;
  auto txn = begin_res.value();

  // Process each product update using sqlgen's type-safe query building
  for (const auto& [product_id, quantity] : received) {
    // Build UPDATE statement using sqlgen's fluent API
    auto update_stmt = update<Product>(
        "stock"_c.set("stock"_c + quantity)
    ) | where("product_id"_c == product_id);

    // Execute the update statement
    auto exec_res = update_stmt(txn);
    if (!exec_res) {
      // Rollback transaction on failure
      auto rollback_res = rollback(txn);
      return false;
    }
  }

  // Commit transaction if all updates succeeded
  auto commit_res = commit(txn);
  return commit_res.has_value();
}

}  // namespace update_inventory_stock
```

## Key Changes Made:

1. **Removed raw SQL strings**: Replaced the manual SQL string construction with sqlgen's type-safe query building
2. **Used column literal operator**: `"stock"_c` and `"product_id"_c` to reference table columns
3. **Used set function with + operator**: `"stock"_c.set("stock"_c + quantity)` to increment stock
4. **Used where function**: `where("product_id"_c == product_id)` to specify the condition
5. **Used update function**: `update<Product>(...)` to build the UPDATE statement
6. **Proper error handling**: Added rollback on individual update failures

## How it Works:

- The `update<Product>` function creates an UPDATE statement for the Product table
- The `set` function with the `+` operator creates an arithmetic expression that adds the received quantity to the current stock
- The `where` function filters for the specific product ID
- The `operator|` chains the WHERE clause to the UPDATE statement
- The resulting statement object is executed by calling it with the transaction connection

This implementation ensures type safety, prevents SQL injection, and follows sqlgen's principles of fluent API design.

